import React from 'react';
import {
  Platform,
  TouchableOpacity,
  Text
} from 'react-native';
import InAppBilling from 'react-native-billing';
import ApplePay from 'react-native-apple-pay';

class PaymentModule extends React.Component {
  state = {
    productDetails: null,
    transactionDetails: null,
  };

  openPaymentGateway = async () => {
    try {
      await InAppBilling.open();

      const details = await InAppBilling.getProductDetails('premium');
      this.setState({ productDetails: details});

      const transactionStatus = await InAppBilling.purchase('premium');
      this.setState({ transactionDetails: transactionStatus });
    } catch (err) {
      console.log(err);
    } finally {
      await InAppBilling.close();
    }
  };

  makeApplePayPayment = async () => {
    try {
      const items = [{label: 'Premium', amount: '0.99'}];
      const shippingMethods = [
        {identifier: 'NextDay', detail: 'Arrives tomorrow', amount: '10.00'}
      ];

      const paymentRequest = {
        merchantIdentifier: 'merchant.com.example',
        items,
        shippingMethods,
        countryCode: 'US',
        currencyCode: 'USD',
        shippingType: 'shipping'
      };

      const token = await ApplePay.makePaymentRequest(paymentRequest);
      this.setState({ transactionDetails: token });
    } catch (err) {
      console.log(err);
    }
  };

  handlePayment = () => {
    if (Platform.OS === 'android') {
      this.openPaymentGateway();
    } else if (Platform.OS === 'ios') {
      this.makeApplePayPayment();
    }
  };

  render() {
    return (
      <TouchableOpacity onPress={this.handlePayment}>
        <Text>Purchase Premium</Text>
      </TouchableOpacity>
    );
  }
}

export default PaymentModule;